174→            ToastUtils.showToast(this, getString(R.string.error_refresh_comments_showing_older));
175→            return;
176→        } else if (!mCanLoadMoreComments) {
177→            AppLog.w(AppLog.T.COMMENTS, "no more comments to be loaded");
178→            return;
179→        }
180→
181→        if (mSite != null && mStatusFilter != null && mAdapter != null) {
182→            mCommentsStoreAdapter.dispatch(CommentActionBuilder.newFetchCommentsAction(
183→                    new FetchCommentsPayload(mSite, mStatusFilter, COMMENTS_PER_PAGE, mAdapter.getCount()))
184→            );
185→            mIsUpdatingComments = true;
186→            setLoadingState(binding, true);
187→        }
188→    }
